```java
@Service
public class OrderRouterService {
    private final NseClient client;
    OrderRouterService(NseClient c) { client = c; }

    @CircuitBreaker(name = "nse-gateway", fallbackMethod = "orderFailed")
    @Retry(name = "nse-gateway")
    public OrderAck submitOrder(Order order) throws IOException {
        return client.submit(order);
    }

    private OrderAck orderFailed(Order order, Exception e) {
        log.error("Order submission failed after retries: {}", e.getMessage());
        return OrderAck.rejected(order.getId(), "NSE_UNAVAILABLE");
    }
}
```

